  1→import React, { useState, useMemo, useCallback, useEffect, useRef } from 'react';
  2→import { View } from 'react-native';
  3→import type {
  4→  SDUIScreen,
  5→  SDUIComponent,
  6→  SDUIComponentRegistry,
  7→  SDUIComponentProps,
  8→  SDUIContext,
  9→  SDUIConditional,
 10→  SDUIActionDescriptor,
 11→  SDUIActionRegistry,
 12→  SDUIActionDeps,
 13→  SDUIActionContext,
 14→} from '../models';
 15→import { interpolateDeep } from '../utils/interpolation';
 16→import { evaluateRule } from '../utils/jsonLogic';
 17→import { getDefaultRegistry, getRenderer } from '../registry';
 18→import { executeAction, executeActions } from '../actions/registry';
 19→import FallbackComponent from './FallbackComponent';
 20→
 21→interface ScreenRendererProps {
 22→  screen: SDUIScreen;
 23→  registry?: SDUIComponentRegistry;
 24→  actionRegistry?: SDUIActionRegistry;
 25→  actionDeps?: Omit<SDUIActionDeps, 'signal'>;
 26→}
 27→
 28→function isConditional(value: unknown): value is SDUIConditional {
 29→  return (
 30→    value !== null &&
 31→    typeof value === 'object' &&
 32→    'rule' in (value as Record<string, unknown>) &&
 33→    typeof (value as Record<string, unknown>).rule === 'object'
 34→  );
 35→}
 36→
 37→function isVisible(component: SDUIComponent, context: SDUIContext): boolean {
 38→  if (!component.visible) return true;
 39→  const { rule } = component.visible;
 40→  if (!rule || typeof rule !== 'object' || Object.keys(rule).length === 0) {
 41→    return true;
 42→  }
 43→  return evaluateRule(rule, context);
 44→}
 45→
 46→function separateConditionals(props: SDUIComponentProps): {
 47→  interpolatable: SDUIComponentProps;
 48→  conditionals: Record<string, SDUIConditional>;
 49→} {
 50→  const interpolatable: SDUIComponentProps = {};
 51→  const conditionals: Record<string, SDUIConditional> = {};
 52→
 53→  for (const key of Object.keys(props)) {
 54→    if (isConditional(props[key])) {
 55→      conditionals[key] = props[key] as SDUIConditional;
 56→    } else {
 57→      interpolatable[key] = props[key];
 58→    }
 59→  }
 60→
 61→  return { interpolatable, conditionals };
 62→}
 63→
 64→function renderComponent(
 65→  component: SDUIComponent,
 66→  context: SDUIContext,
 67→  registry: SDUIComponentRegistry,
 68→  key: string,
 69→  onAction?: (descriptor: SDUIActionDescriptor) => void,
 70→) {
 71→  if (!isVisible(component, context)) return null;
 72→
 73→  const { interpolatable, conditionals } = separateConditionals(component.props);
 74→  const interpolatedProps = {
 75→    ...interpolateDeep(interpolatable, context),
 76→    ...conditionals,
 77→  };
 78→
 79→  const Renderer = getRenderer(registry, component.type);
 80→
 81→  if (!Renderer) {
 82→    return (
 83→      <FallbackComponent
 84→        key={key}
 85→        type={component.type}
 86→        props={interpolatedProps}
 87→      />
 88→    );
 89→  }
 90→
 91→  return (
 92→    <Renderer
 93→      key={key}
 94→      props={interpolatedProps}
 95→      context={context}
 96→      onAction={onAction}
 97→    />
 98→  );
 99→}
100→
101→export default function ScreenRenderer({
102→  screen,
103→  registry,
104→  actionRegistry,
105→  actionDeps,
106→}: ScreenRendererProps) {
107→  const activeRegistry = registry ?? getDefaultRegistry();
108→  const { context, header, body, footer } = screen;
109→
110→  const [formState, setForm] = useState<Record<string, unknown>>({});
111→
112→  const abortControllerRef = useRef<AbortController | null>(null);
113→
114→  useEffect(() => {
115→    const controller = new AbortController();
116→    abortControllerRef.current = controller;
117→    return () => {
118→      controller.abort();
119→      abortControllerRef.current = null;
120→    };
121→  }, []);
122→
123→  const mergedContext = useMemo<SDUIContext>(
124→    () => ({ ...context, form: formState as unknown as SDUIContext }),
125→    [context, formState],
126→  );
127→
128→  const actionContext = useMemo<SDUIActionContext>(
129→    () => ({
130→      screen: context,
131→      form: formState,
132→      setForm,
133→    }),
134→    [context, formState],
135→  );
136→
137→  const onAction = useCallback(
138→    (descriptor: SDUIActionDescriptor) => {
139→      if (!actionRegistry) return;
140→
141→      const deps: SDUIActionDeps = {
142→        ...actionDeps,
143→        signal: abortControllerRef.current?.signal,
144→      };
145→
146→      executeAction(actionRegistry, descriptor, actionContext, deps);
147→    },
148→    [actionRegistry, actionDeps, actionContext],
149→  );
150→
151→  const onActions = useCallback(
152→    (descriptors: SDUIActionDescriptor[]) => {
153→      if (!actionRegistry) return;
154→
155→      const deps: SDUIActionDeps = {
156→        ...actionDeps,
157→        signal: abortControllerRef.current?.signal,
158→      };
159→
160→      executeActions(actionRegistry, descriptors, actionContext, deps);
161→    },
162→    [actionRegistry, actionDeps, actionContext],
163→  );
164→
165→  const actionHandler = actionRegistry ? onAction : undefined;
166→
167→  return (
168→    <View style={{ flex: 1 }}>
169→      {header &&
170→        renderComponent(header, mergedContext, activeRegistry, 'header', actionHandler)}
171→
172→      <View style={{ flex: 1 }}>
173→        {(body ?? []).map((component, index) =>
174→          renderComponent(
175→            component,
176→            mergedContext,
177→            activeRegistry,
178→            `${component.type}-${index}`,
179→            actionHandler,
180→          ),
181→        )}
182→      </View>
183→
184→      {footer &&
185→        renderComponent(footer, mergedContext, activeRegistry, 'footer', actionHandler)}
186→    </View>
187→  );
188→}
