 21→
 22→const ButtonAdapter = ({
 23→  props,
 24→}: {
 25→  props: SDUIComponentProps;
 26→  context: SDUIContext;
 27→}) => <Text testID="button">{String(props.label)}</Text>;
 28→
 29→const ActionButtonAdapter = ({
 30→  props,
 31→  onAction,
 32→}: {
 33→  props: SDUIComponentProps;
 34→  context: SDUIContext;
 35→  onAction?: (descriptor: SDUIActionDescriptor) => void;
 36→}) => (
 37→  <Pressable
 38→    testID="action-button"
 39→    onPress={() => {
 40→      if (onAction && props.action) {
 41→        onAction(props.action as unknown as SDUIActionDescriptor);
