 45→function buildMergedContext(actionContext: SDUIActionContext): SDUIContext {
 46→  return {
 47→    ...actionContext.screen,
 48→    form: actionContext.form as unknown as SDUIContext,
 49→  };
 50→}
 51→
 52→export async function executeAction(
 53→  registry: SDUIActionRegistry,
 54→  descriptor: SDUIActionDescriptor,
 55→  actionContext: SDUIActionContext,
 56→  deps: SDUIActionDeps,
 57→): Promise<SDUIActionResult> {
 58→  const handler = registry[descriptor.type];
 59→  if (!handler) {
 60→    if (__DEV__) {
 61→      console.warn(`[SDUI] Unknown action type: "${descriptor.type}"`);
 62→    }
 63→    return { success: false, error: `Unknown action type: "${descriptor.type}"` };
 64→  }
 65→
 66→  const mergedContext = buildMergedContext(actionContext);
 67→  const interpolatedPayload = descriptor.payload
 68→    ? interpolateDeep(descriptor.payload, mergedContext)
 69→    : undefined;
 70→
 71→  try {
 72→    return await handler(interpolatedPayload, actionContext, deps);
 73→  } catch (err) {
 74→    const message = err instanceof Error ? err.message : String(err);
 75→    if (__DEV__) {
 76→      console.error(`[SDUI] Action "${descriptor.type}" threw:`, message);
 77→    }
 78→    return { success: false, error: message };
 79→  }
 80→}
