 82→export async function executeActions(
 83→  registry: SDUIActionRegistry,
 84→  descriptors: SDUIActionDescriptor[],
 85→  actionContext: SDUIActionContext,
 86→  deps: SDUIActionDeps,
 87→): Promise<SDUIActionResult[]> {
 88→  const results: SDUIActionResult[] = new Array(descriptors.length);
 89→
 90→  const analyticsIndices: number[] = [];
 91→  const primaryIndices: number[] = [];
 92→
 93→  for (let i = 0; i < descriptors.length; i++) {
 94→    if (ANALYTICS_ACTIONS.has(descriptors[i].type)) {
 95→      analyticsIndices.push(i);
 96→    } else {
 97→      primaryIndices.push(i);
 98→    }
 99→  }
100→
101→  for (const i of primaryIndices) {
102→    if (deps.signal?.aborted) {
103→      results[i] = { success: false, error: 'Aborted' };
104→      continue;
105→    }
106→    results[i] = await executeAction(registry, descriptors[i], actionContext, deps);
107→  }
108→
109→  for (const i of analyticsIndices) {
110→    results[i] = await executeAction(registry, descriptors[i], actionContext, deps);
111→  }
112→
113→  return results;
114→}
